---
import { Moon, Sun } from "@lucide/astro"

import { cn } from "@/lib/utils"
import { Button, type ButtonVariantProps } from "@/components/ui/button"

interface Props extends ButtonVariantProps {
  class?: string
}

const { class: className, variant = "outline", size = "icon-sm" } = Astro.props
---

<Button
  data-theme-toggle
  aria-label="Toggle theme"
  variant={variant}
  size={size}
  class={cn("relative", className)}
>
  <Sun class="h-[1.2rem] w-[1.2rem] scale-100 rotate-0 transition-all dark:scale-0 dark:-rotate-90" />
  <Moon class="absolute h-[1.2rem] w-[1.2rem] scale-0 rotate-90 transition-all dark:scale-100 dark:rotate-0" />
  <span class="sr-only">Toggle theme</span>
</Button>

<script is:inline>
  if (!window.__themeToggleHandlersInitialized) {
    window.__themeToggleHandlersInitialized = true

    const syncThemeToggles = () => {
      const isDark = document.documentElement.classList.contains("dark")

      document.querySelectorAll("[data-theme-toggle]").forEach((toggle) => {
        if (!(toggle instanceof HTMLButtonElement)) return

        toggle.setAttribute("aria-pressed", isDark ? "true" : "false")
        toggle.setAttribute("data-state", isDark ? "on" : "off")

        if (isDark) {
          toggle.setAttribute("data-pressed", "")
        } else {
          toggle.removeAttribute("data-pressed")
        }
      })
    }

    syncThemeToggles()

    const observer = new MutationObserver(syncThemeToggles)

    observer.observe(document.documentElement, {
      attributes: true,
      attributeFilter: ["class"],
    })

    document.addEventListener("click", (event) => {
      const target = event.target

      if (!(target instanceof Element)) return

      const toggle = target.closest("[data-theme-toggle]")

      if (!(toggle instanceof HTMLButtonElement)) return
      if (toggle.disabled) return

      document.documentElement.classList.toggle("dark")
    })
  }
</script>
